const MAPPING = {
  'STUDIO 1 REFORMER': 'Pilates',
  'STUDIO 2 REFORMER': 'Pilates',
  'IN-TRINITY': 'In-Trinity',
  'WBS POSTURALE': 'WBS',
  'PILOGA': 'Piloga',
  'SHAPE & TONE': 'Functional',
  'EASY STUDIO 1': 'Easy Reformer',
  'EASY STUDIO 2': 'Easy Reformer',
  'WBS EASY POSTURALE': 'Easy WBS',
  'ESTATE REFORMER': 'Pilates',
  'ESTATE WBS': 'WBS',
};

const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { skip: true, motivo: 'Nessuna lezione ieri' } }];
}

const data = rows[0].json.data;
const items = rows.map(r => {
  const att = MAPPING[r.json.corso_dbgym];
  if (!att) return null;
  return {
    attivita: att,
    oraInizio: r.json.ora,
    partecipanti: r.json.partecipanti
  };
}).filter(Boolean);

return [{ json: { data, items, skip: false } }];

const result = $input.first().json;
const skipData = $('Mapping Nomi').first().json;

let text;
if (skipData.skip) {
  text = `🔄 *Sync Partecipanti*\nNessuna lezione ieri — skip.`;
} else {
  text = `🔄 *Sync Partecipanti*\n📅 ${result.data || skipData.data}\n✅ Aggiornate: ${result.aggiornate || 0}\n⚠️ Non trovate: ${result.nonTrovate || 0}`;
  if (result.dettagli) {
    for (const d of result.dettagli) {
      const icon = d.registrazioni > 0 ? '✅' : '❌';
      text += `\n${icon} ${d.attivita} ${d.oraInizio} → ${d.partecipanti} pers. (${d.registrazioni} reg.)`;
    }
  }
}

return [{ json: { text } }];
